#nullable enable // autogenerated

using PVZEngine.Definitions;
using PVZEngine.Level;

namespace MVZ2.GameContent.Stages
{
    [AutoStageDefinition(VanillaStageNames.heavyWeapon)]
    public partial class HeavyWeaponStage : StageDefinition
    {
        public HeavyWeaponStage(string nsp, string name) : base(nsp, name)
        {
            AddBehaviour(new WaveStageBehaviour(this));
            AddBehaviour(new FinalWaveClearBehaviour(this));
            AddBehaviour(new GemStageBehaviour(this));
            AddBehaviour(new RedstoneDropStageBehaviour(this));
            AddBehaviour(new HeavyWeaponStageBehaviour(this));
            AddBehaviour(new SpeedUpStageBehaviour(this, 1.5f, 2f));
        }
    }
}
